function copyLink(){const e=Date.now().toString(),t=document.querySelector("#inlink"),o=document.querySelector("form .btn-copy");navigator.clipboard.writeText(t.value).then(()=>{o.classList.add(`success-${e}`),t.select(),t.setSelectionRange(0,t.value.length),setTimeout(()=>{o.classList.remove(`success-${e}`)},850)}).catch(t=>{console.error("Failed to copy: ",t),o.classList.add(`failure-${e}`),setTimeout(()=>{o.classList.remove(`failure-${e}`)},850)})}function shortenLink(){const e=document.querySelector('dropmenu[data-type="shortening"] input').value,t=document.querySelector("#inlink"),o=document.querySelector("form .btn-newtab");shortening[e](t.value).then(e=>{if("string"!=typeof e)throw e;t.value=e,o.setAttribute("href",e),window.history.pushState(null,"","/?x="+encodeURIComponent(e.replace(/^https:\/\//,"")))}).catch(e=>{console.error("Failed to copy: ",e)})}document.querySelector("form .btn-copy").addEventListener("click",copyLink),document.querySelector("form .btn-shorten").addEventListener("click",shortenLink),window.addEventListener("popstate",()=>{window.location.reload()});